const BATCH_SIZE = 10;

const SYSTEM_PROMPT = `Bạn là chuyên gia chuẩn hóa tiếng Việt. Nhiệm vụ của bạn là chuyển các tin nhắn lừa đảo/spam viết bằng "leet speak" tiếng Việt thành tiếng Việt chuẩn có đầy đủ dấu.

Quy tắc:
- Giữ nguyên tên thương hiệu viết hoa (SACOMBANK, MSB, BIDV, v.v.)
- Giữ nguyên URL/link (không thay đổi domain)
- Giữ nguyên số điện thoại và số tiền
- Giữ nguyên các từ viết tắt tiếng Anh (CTV, CSKH, DK, VND)
- Chuyển đổi leet speak thành tiếng Việt chuẩn có dấu (ví dụ: "t41 kh04n" → "tài khoản", "b4o c4o" → "báo cáo", "z3" → "để", "v40" → "vào")
- Giữ nguyên hashtag, mã giới thiệu ngắn (t.ly/xxx)
- Trả về JSON thuần túy, không có backtick hay markdown

Trả về JSON với định dạng:
{"results": [{"id": 1234, "content_after": "nội dung tiếng Việt chuẩn"}]}`;

export default function App() {
  const [rows, setRows] = useState(RAW_DATA.map(r => ({ ...r, content_after: "", status: "pending" })));
  const [running, setRunning] = useState(false);
  const [progress, setProgress] = useState(0);
  const [copied, setCopied] = useState(false);

  const processBatch = useCallback(async (batch) => {
    const payload = batch.map(r => ({ id: r.id, text: r.content_before }));
    const userMsg = `Chuẩn hóa các tin nhắn sau thành tiếng Việt chuẩn có dấu:\n${JSON.stringify(payload, null, 2)}`;

    const response = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        model: "claude-sonnet-4-20250514",
        max_tokens: 1000,
        system: SYSTEM_PROMPT,
        messages: [{ role: "user", content: userMsg }],
      }),
    });

    const data = await response.json();
    const text = data.content?.map(c => c.text || "").join("") || "";
    const clean = text.replace(/```json|```/g, "").trim();
    const parsed = JSON.parse(clean);
    return parsed.results;
  }, []);

  const runAll = useCallback(async () => {
    setRunning(true);
    setProgress(0);
    const updated = [...rows];

    for (let i = 0; i < RAW_DATA.length; i += BATCH_SIZE) {
      const batch = RAW_DATA.slice(i, i + BATCH_SIZE);
      try {
        // Mark as processing
        batch.forEach(r => {
          const idx = updated.findIndex(u => u.id === r.id);
          if (idx !== -1) updated[idx].status = "processing";
        });
        setRows([...updated]);

        const results = await processBatch(batch);
        results.forEach(res => {
          const idx = updated.findIndex(u => u.id === res.id);
          if (idx !== -1) {
            updated[idx].content_after = res.content_after;
            updated[idx].status = "done";
          }
        });
      } catch (err) {
        batch.forEach(r => {
          const idx = updated.findIndex(u => u.id === r.id);
          if (idx !== -1) updated[idx].status = "error";
        });
      }
      setRows([...updated]);
      setProgress(Math.min(i + BATCH_SIZE, RAW_DATA.length));
    }

    setRunning(false);
  }, [rows, processBatch]);

  const exportCSV = useCallback(() => {
    const header = "id,category,content_before,content_after";
    const lines = rows.map(r =>
      `${r.id},"${r.cat}","${r.content_before.replace(/"/g, '""')}","${(r.content_after || "").replace(/"/g, '""')}"`
    );
    const csv = [header, ...lines].join("\n");
    const blob = new Blob(["\uFEFF" + csv], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = "content_after_normalized.csv";
    a.click();
    URL.revokeObjectURL(url);
  }, [rows]);

  const copyAll = useCallback(() => {
    const lines = rows.map(r => `${r.id}\t${r.content_after || ""}`).join("\n");
    navigator.clipboard.writeText(lines);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  }, [rows]);

  const done = rows.filter(r => r.status === "done").length;
  const pct = Math.round((done / rows.length) * 100);

  const statusColor = (s) => {
    if (s === "done") return "#22c55e";
    if (s === "processing") return "#f59e0b";
    if (s === "error") return "#ef4444";
    return "#94a3b8";
  };

  return (
    <div style={{
      fontFamily: "'IBM Plex Mono', monospace",
      background: "#0f1117",
      minHeight: "100vh",
      color: "#e2e8f0",
      padding: "24px",
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Mono:wght@400;500;600&family=IBM+Plex+Sans+Vietnamese:wght@400;500;600&display=swap');
        ::-webkit-scrollbar { width: 6px; }
        ::-webkit-scrollbar-track { background: #1e2330; }
        ::-webkit-scrollbar-thumb { background: #334155; border-radius: 3px; }
        .row-card { transition: background 0.2s; }
        .row-card:hover { background: #1a2035 !important; }
        .btn { cursor: pointer; border: none; border-radius: 6px; font-family: inherit; font-size: 13px; font-weight: 600; padding: 10px 20px; transition: all 0.15s; letter-spacing: 0.03em; }
        .btn:disabled { opacity: 0.4; cursor: not-allowed; }
        .btn-primary { background: #3b82f6; color: #fff; }
        .btn-primary:not(:disabled):hover { background: #2563eb; }
        .btn-ghost { background: #1e2330; color: #94a3b8; border: 1px solid #334155; }
        .btn-ghost:not(:disabled):hover { background: #263045; color: #e2e8f0; }
        .tag { display: inline-block; font-size: 10px; padding: 2px 8px; border-radius: 4px; font-weight: 600; letter-spacing: 0.05em; }
      `}</style>

      {/* Header */}
      <div style={{ marginBottom: 28 }}>
        <div style={{ fontSize: 11, color: "#64748b", letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 6 }}>
          Vietnamese Leet Normalizer
        </div>
        <h1 style={{ margin: 0, fontSize: 22, fontWeight: 600, color: "#f1f5f9", letterSpacing: "-0.02em" }}>
          content_after — Chuẩn hóa tiếng Việt
        </h1>
        <p style={{ margin: "8px 0 0", fontSize: 13, color: "#64748b" }}>
          {rows.length} tin nhắn · Xử lý theo batch {BATCH_SIZE}
        </p>
      </div>

      {/* Controls */}
      <div style={{ display: "flex", gap: 10, marginBottom: 20, flexWrap: "wrap", alignItems: "center" }}>
        <button className="btn btn-primary" onClick={runAll} disabled={running}>
          {running ? `⏳ Đang xử lý... ${done}/${rows.length}` : "▶ Chạy tất cả"}
        </button>
        <button className="btn btn-ghost" onClick={exportCSV} disabled={done === 0}>
          ⬇ Xuất CSV
        </button>
        <button className="btn btn-ghost" onClick={copyAll} disabled={done === 0}>
          {copied ? "✓ Đã copy!" : "⧉ Copy kết quả"}
        </button>

        {running || done > 0 ? (
          <div style={{ display: "flex", alignItems: "center", gap: 10, marginLeft: 8 }}>
            <div style={{ width: 140, height: 6, background: "#1e2330", borderRadius: 99, overflow: "hidden" }}>
              <div style={{ width: `${pct}%`, height: "100%", background: "#3b82f6", borderRadius: 99, transition: "width 0.4s" }} />
            </div>
            <span style={{ fontSize: 12, color: "#64748b" }}>{pct}%</span>
          </div>
        ) : null}
      </div>

      {/* Table */}
      <div style={{ borderRadius: 10, overflow: "hidden", border: "1px solid #1e2330" }}>
        {/* Header row */}
        <div style={{
          display: "grid",
          gridTemplateColumns: "56px 160px 1fr 1fr 60px",
          gap: 0,
          background: "#141824",
          borderBottom: "1px solid #1e2330",
          padding: "10px 16px",
          fontSize: 11,
          color: "#475569",
          letterSpacing: "0.08em",
          textTransform: "uppercase",
          fontWeight: 600,
        }}>
          <div>ID</div>
          <div>Danh mục</div>
          <div>Content before</div>
          <div>Content after ✨</div>
          <div>Status</div>
        </div>

        {rows.map((r, i) => (
          <div key={r.id} className="row-card" style={{
            display: "grid",
            gridTemplateColumns: "56px 160px 1fr 1fr 60px",
            gap: 0,
            background: i % 2 === 0 ? "#0f1117" : "#111520",
            borderBottom: "1px solid #1a1f2e",
            padding: "12px 16px",
            alignItems: "start",
            fontSize: 12,
            lineHeight: 1.6,
            fontFamily: "'IBM Plex Sans Vietnamese', sans-serif",
          }}>
            <div style={{ color: "#475569", paddingTop: 2, fontFamily: "IBM Plex Mono" }}>{r.id}</div>
            <div>
              <span className="tag" style={{
                background: r.cat.includes("ngân hàng") ? "#1e3a5f" : "#2d1f4e",
                color: r.cat.includes("ngân hàng") ? "#60a5fa" : "#a78bfa",
              }}>
                {r.cat.includes("ngân hàng") ? "🏦 Ngân hàng" : "🎲 Betting"}
              </span>
            </div>
            <div style={{ color: "#94a3b8", paddingRight: 16, fontSize: 11.5 }}>{r.content_before}</div>
            <div style={{
              color: r.status === "done" ? "#e2e8f0" : r.status === "processing" ? "#fbbf24" : "#334155",
              paddingRight: 16,
              fontSize: 11.5,
              minHeight: 20,
            }}>
              {r.status === "processing" ? (
                <span style={{ color: "#f59e0b" }}>⏳ Đang xử lý...</span>
              ) : r.content_after || (
                <span style={{ color: "#334155", fontSize: 11 }}>—</span>
              )}
            </div>
            <div>
              <div style={{
                width: 8, height: 8, borderRadius: "50%",
                background: statusColor(r.status),
                marginTop: 6,
                boxShadow: r.status === "processing" ? `0 0 6px ${statusColor(r.status)}` : "none",
              }} />
            </div>
          </div>
        ))}
      </div>

      <div style={{ marginTop: 16, fontSize: 11, color: "#334155", textAlign: "center" }}>
        {done} / {rows.length} đã hoàn thành · Xuất CSV để lấy toàn bộ dữ liệu
      </div>
    </div>
  );
}
